solutions.javascript:
// Solution
function getMediaQueryPriority(cssRule) {
  let mediaQueryStart = cssRule.indexOf('@media');
  if (mediaQueryStart === -1) return 0;
  let count = 0;
  let i;
  for (i = mediaQueryStart + 6; i < cssRule.length; i++) {
    if (cssRule[i] === ' ' || cssRule[i] === 'a' || cssRule[i] === 'o') {
      count++;
    }
  }
  return count;
}

solutions.python:
class Solution:
  def get_media_query_priority(self, css_rule: str) -> int:
    media_query_start = css_rule.find('@media')
    if media_query_start == -1:
      return 0
    count = 0
    for i in range(media_query_start + 6, len(css_rule)):
      if css_rule[i] == ' ' or css_rule[i] == 'a' or css_rule[i] == 'o':
        count++
    return count
